  TOKEN_EXPIRY: '@auth/token_expiry',

  // Profile
  USER_PROFILE: '@user/profile',
  USER_PREFERENCES: '@user/preferences',

  // Session
  SESSION_DATA: '@session/data',
  LAST_ACTIVE: '@session/last_active',
