// ==================== Preferences Manager ====================

class PreferencesManager {
  static async savePreferences(preferences) {
    const merged = { ...DEFAULT_PREFERENCES, ...preferences };
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, merged);
  }

  static async getPreferences() {
    const prefs = await StorageHelper.get(STORAGE_KEYS.USER_PREFERENCES);
    return prefs ? { ...DEFAULT_PREFERENCES, ...prefs } : { ...DEFAULT_PREFERENCES };
  }

  static async updatePreference(key, value) {
    const prefs = await this.getPreferences();
    prefs[key] = value;
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, prefs);
  }

  static async addToRecentSearches(query, maxItems = 20) {
    const prefs = await this.getPreferences();
    const searches = prefs.recentSearches || [];
    // Remove duplicate if exists
    const filtered = searches.filter(s => s.query !== query);
    filtered.unshift({ query, timestamp: Date.now() });
    prefs.recentSearches = filtered.slice(0, maxItems);
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, prefs);
  }

  static async addBookmark(item) {
    const prefs = await this.getPreferences();
    const bookmarks = prefs.bookmarks || [];
    if (!bookmarks.find(b => b.id === item.id)) {
      bookmarks.push({ ...item, bookmarkedAt: Date.now() });
      prefs.bookmarks = bookmarks;
      return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, prefs);
    }
    return true;
  }

  static async removeBookmark(itemId) {
    const prefs = await this.getPreferences();
    prefs.bookmarks = (prefs.bookmarks || []).filter(b => b.id !== itemId);
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, prefs);
  }

  static async addToViewHistory(item, maxItems = 50) {
    const prefs = await this.getPreferences();
    const history = prefs.viewHistory || [];
    const filtered = history.filter(h => h.id !== item.id);
    filtered.unshift({ ...item, viewedAt: Date.now() });
    prefs.viewHistory = filtered.slice(0, maxItems);
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, prefs);
  }

  static async clearPreferences() {
    return StorageHelper.set(STORAGE_KEYS.USER_PREFERENCES, { ...DEFAULT_PREFERENCES });
  }
}

// ==================== Session Manager ====================

class SessionManager {
  static async createSession(sessionData) {
    const session = {
      ...sessionData,
      id: sessionData.id || `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      createdAt: Date.now(),
      lastActive: Date.now(),
    };
    await StorageHelper.multiSet([
      [STORAGE_KEYS.SESSION_DATA, session],
      [STORAGE_KEYS.SESSION_ID, session.id],
      [STORAGE_KEYS.LAST_ACTIVE, session.lastActive],
    ]);
    return session;
  }

  static async getSession() {
    return StorageHelper.get(STORAGE_KEYS.SESSION_DATA);
  }

  static async updateLastActive() {
    const now = Date.now();
    const session = await this.getSession();
    if (session) {
      session.lastActive = now;
      await StorageHelper.multiSet([
        [STORAGE_KEYS.SESSION_DATA, session],
        [STORAGE_KEYS.LAST_ACTIVE, now],
      ]);
    }
    return now;
  }

  static async updateSessionData(updates) {
    const session = await this.getSession();
    if (!session) return null;
    const updated = { ...session, ...updates, lastActive: Date.now() };
    await StorageHelper.set(STORAGE_KEYS.SESSION_DATA, updated);
    return updated;
  }

  static async isSessionValid(maxInactiveMs = 1800000) {
    // Default: 30 minutes
    const lastActive = await StorageHelper.get(STORAGE_KEYS.LAST_ACTIVE);
    if (!lastActive) return false;
    return (Date.now() - lastActive) < maxInactiveMs;
  }

  static async getSessionDuration() {
    const session = await this.getSession();
    if (!session || !session.createdAt) return 0;
    return Date.now() - session.createdAt;
  }

  static async clearSession() {
    return StorageHelper.multiRemove([
      STORAGE_KEYS.SESSION_DATA,
      STORAGE_KEYS.SESSION_ID,
      STORAGE_KEYS.LAST_ACTIVE,
    ]);
  }
}

