// ==================== Offline Content Manager ====================

class OfflineContentManager {
  static async saveContent(key, content, ttl = 3600000) {
    const contentStore = await StorageHelper.get(STORAGE_KEYS.OFFLINE_CONTENT) || {};
    contentStore[key] = {
      data: content,
      cachedAt: Date.now(),
      expiresAt: Date.now() + ttl,
    };
    // Update cache metadata
    const metadata = await StorageHelper.get(STORAGE_KEYS.CACHE_METADATA) || {};
    metadata[key] = {
      size: JSON.stringify(content).length,
      cachedAt: Date.now(),
      expiresAt: Date.now() + ttl,
    };
    await StorageHelper.set(STORAGE_KEYS.CACHE_METADATA, metadata);
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_CONTENT, contentStore);
  }

  static async getContent(key) {
    const contentStore = await StorageHelper.get(STORAGE_KEYS.OFFLINE_CONTENT) || {};
    const item = contentStore[key];
    if (!item) return null;
    // Check if expired
    if (Date.now() > item.expiresAt) {
      delete contentStore[key];
      await StorageHelper.set(STORAGE_KEYS.OFFLINE_CONTENT, contentStore);
      // Clean metadata too
      const metadata = await StorageHelper.get(STORAGE_KEYS.CACHE_METADATA) || {};
      delete metadata[key];
      await StorageHelper.set(STORAGE_KEYS.CACHE_METADATA, metadata);
      return null;
    }
    return item.data;
  }

  static async isContentCached(key) {
    const content = await this.getContent(key);
    return content !== null;
  }

  static async removeContent(key) {
    const contentStore = await StorageHelper.get(STORAGE_KEYS.OFFLINE_CONTENT) || {};
    delete contentStore[key];
    const metadata = await StorageHelper.get(STORAGE_KEYS.CACHE_METADATA) || {};
    delete metadata[key];
    await StorageHelper.set(STORAGE_KEYS.CACHE_METADATA, metadata);
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_CONTENT, contentStore);
  }

  static async clearExpiredContent() {
    const contentStore = await StorageHelper.get(STORAGE_KEYS.OFFLINE_CONTENT) || {};
    const metadata = await StorageHelper.get(STORAGE_KEYS.CACHE_METADATA) || {};
    const now = Date.now();
    let cleared = 0;

    Object.keys(contentStore).forEach(key => {
      if (contentStore[key].expiresAt < now) {
        delete contentStore[key];
        delete metadata[key];
        cleared++;
      }
    });

    if (cleared > 0) {
      await StorageHelper.set(STORAGE_KEYS.OFFLINE_CONTENT, contentStore);
      await StorageHelper.set(STORAGE_KEYS.CACHE_METADATA, metadata);
    }

    return cleared;
  }

  static async clearAllContent() {
    await StorageHelper.set(STORAGE_KEYS.OFFLINE_CONTENT, {});
    await StorageHelper.set(STORAGE_KEYS.CACHE_METADATA, {});
    return true;
  }

  static async getCacheStats() {
    const metadata = await StorageHelper.get(STORAGE_KEYS.CACHE_METADATA) || {};
    const keys = Object.keys(metadata);
    const now = Date.now();
    let totalSize = 0;
    let expiredCount = 0;

    keys.forEach(key => {
      totalSize += metadata[key].size || 0;
      if (metadata[key].expiresAt < now) {
        expiredCount++;
      }
    });

    return {
      totalItems: keys.length,
      totalSize,
      totalSizeFormatted: formatBytes(totalSize),
      expiredItems: expiredCount,
      activeItems: keys.length - expiredCount,
    };
  }

  // Offline action queue for syncing later
  static async addToQueue(action) {
    const queue = await StorageHelper.get(STORAGE_KEYS.OFFLINE_QUEUE) || [];
    queue.push({
      ...action,
      id: `action_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      queuedAt: Date.now(),
      status: 'pending',
    });
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_QUEUE, queue);
  }

  static async getQueue() {
    return StorageHelper.get(STORAGE_KEYS.OFFLINE_QUEUE) || [];
  }

  static async removeFromQueue(actionId) {
    const queue = await this.getQueue();
    const filtered = queue.filter(a => a.id !== actionId);
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_QUEUE, filtered);
  }

  static async markQueueItemProcessed(actionId) {
    const queue = await this.getQueue();
    const item = queue.find(a => a.id === actionId);
    if (item) {
      item.status = 'processed';
      item.processedAt = Date.now();
    }
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_QUEUE, queue);
  }

  static async clearProcessedQueue() {
    const queue = await this.getQueue();
    const pending = queue.filter(a => a.status === 'pending');
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_QUEUE, pending);
  }

  static async clearQueue() {
    return StorageHelper.set(STORAGE_KEYS.OFFLINE_QUEUE, []);
  }
}

// ==================== Utility Functions ====================

function formatBytes(bytes) {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// ==================== Main Data Manager ====================

class DataManager {
  constructor() {
    this.memoryCache = new MemoryCache(200);
    this.initialized = false;
    this.listeners = new Map();
  }

  // Initialize the data manager
  async initialize() {
    if (this.initialized) return;

    try {
      // Pre-load frequently accessed data into memory cache
      const settings = await SettingsManager.getSettings();
      this.memoryCache.set('settings', settings);

      const profile = await ProfileManager.getProfile();
      if (profile) {
        this.memoryCache.set('profile', profile);
      }

      const preferences = await PreferencesManager.getPreferences();
      this.memoryCache.set('preferences', preferences);

      // Clean expired offline content
      await OfflineContentManager.clearExpiredContent();

      this.initialized = true;
      console.log('[DataManager] Initialized successfully');
    } catch (error) {
      console.error('[DataManager] Initialization error:', error);
    }
  }

  // ---- Event Listeners ----
  subscribe(event, callback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event).push(callback);
    return () => {
      const callbacks = this.listeners.get(event) || [];
      this.listeners.set(event, callbacks.filter(cb => cb !== callback));
    };
  }

  notify(event, data) {
    const callbacks = this.listeners.get(event) || [];
    callbacks.forEach(cb => {
      try {
        cb(data);
      } catch (err) {
        console.error(`[DataManager] Listener error for ${event}:`, err);
      }
    });
  }

  // ---- Token Operations ----
  async saveTokens(accessToken, refreshToken, expiresIn) {
    const result = await TokenManager.saveTokens(accessToken, refreshToken, expiresIn);
    this.memoryCache.set('accessToken', accessToken);
    this.notify('tokensUpdated', { accessToken, refreshToken });
    return result;
  }

  async getAccessToken() {
    const cached = this.memoryCache.get('accessToken');
    if (cached !== undefined) return cached;
    const token = await TokenManager.getAccessToken();
    if (token) this.memoryCache.set('accessToken', token);
    return token;
  }

  async getRefreshToken() {
    return TokenManager.getRefreshToken();
  }

  async isTokenExpired() {
    return TokenManager.isTokenExpired();
  }

  async getTokenInfo() {
    return TokenManager.getTokenInfo();
  }

  // ---- Profile Operations ----
  async saveProfile(profile) {
    const result = await ProfileManager.saveProfile(profile);
    this.memoryCache.set('profile', profile);
    this.notify('profileUpdated', profile);
    return result;
  }

  async getProfile() {
    const cached = this.memoryCache.get('profile');
    if (cached !== undefined) return cached;
    const profile = await ProfileManager.getProfile();
    if (profile) this.memoryCache.set('profile', profile);
    return profile;
  }

  async updateProfile(updates) {
    const result = await ProfileManager.updateProfile(updates);
    if (result) {
      const updated = await ProfileManager.getProfile();
      this.memoryCache.set('profile', updated);
      this.notify('profileUpdated', updated);
    }
    return result;
  }

  // ---- Preferences Operations ----
  async savePreferences(preferences) {
    const result = await PreferencesManager.savePreferences(preferences);
    const prefs = await PreferencesManager.getPreferences();
    this.memoryCache.set('preferences', prefs);
    this.notify('preferencesUpdated', prefs);
    return result;
  }

  async getPreferences() {
    const cached = this.memoryCache.get('preferences');
    if (cached !== undefined) return cached;
    const prefs = await PreferencesManager.getPreferences();
    this.memoryCache.set('preferences', prefs);
    return prefs;
  }

  async updatePreference(key, value) {
    const result = await PreferencesManager.updatePreference(key, value);
    if (result) {
      const prefs = await PreferencesManager.getPreferences();
      this.memoryCache.set('preferences', prefs);
      this.notify('preferencesUpdated', prefs);
    }
    return result;
  }

  async addRecentSearch(query) {
    return PreferencesManager.addToRecentSearches(query);
  }

  async addBookmark(item) {
    return PreferencesManager.addBookmark(item);
  }

  async removeBookmark(itemId) {
    return PreferencesManager.removeBookmark(itemId);
  }

  async addToViewHistory(item) {
    return PreferencesManager.addToViewHistory(item);
  }

  // ---- Session Operations ----
  async createSession(data) {
    const session = await SessionManager.createSession(data);
    this.memoryCache.set('session', session);
    this.notify('sessionCreated', session);
    return session;
  }

  async getSession() {
    const cached = this.memoryCache.get('session');
    if (cached !== undefined) return cached;
    const session = await SessionManager.getSession();
    if (session) this.memoryCache.set('session', session);
    return session;
  }

  async updateLastActive() {
    const result = await SessionManager.updateLastActive();
    this.memoryCache.delete('session');
    return result;
  }

  async isSessionValid(maxInactiveMs) {
    return SessionManager.isSessionValid(maxInactiveMs);
  }

  // ---- Settings Operations ----
  async saveSettings(settings) {
    const result = await SettingsManager.saveSettings(settings);
    const updated = await SettingsManager.getSettings();
    this.memoryCache.set('settings', updated);
    this.notify('settingsUpdated', updated);
    return result;
  }

  async getSettings() {
    const cached = this.memoryCache.get('settings');
    if (cached !== undefined) return cached;
    const settings = await SettingsManager.getSettings();
    this.memoryCache.set('settings', settings);
    return settings;
  }

  async updateSetting(key, value) {
    const result = await SettingsManager.updateSetting(key, value);
    if (result) {
      const settings = await SettingsManager.getSettings();
      this.memoryCache.set('settings', settings);
      this.notify('settingsUpdated', settings);
    }
    return result;
  }

  async getTheme() {
    const settings = await this.getSettings();
    return settings.theme;
  }

  async setTheme(theme) {
    return this.updateSetting('theme', theme);
  }

  async getLanguage() {
    const settings = await this.getSettings();
    return settings.language;
  }

  async setLanguage(language) {
    return this.updateSetting('language', language);
  }

  // ---- Offline Content Operations ----
  async cacheContent(key, content, ttl) {
    const result = await OfflineContentManager.saveContent(key, content, ttl);
    this.memoryCache.set(`offline_${key}`, content);
    return result;
  }

  async getCachedContent(key) {
    const memoryCached = this.memoryCache.get(`offline_${key}`);
    if (memoryCached !== undefined) return memoryCached;
    const content = await OfflineContentManager.getContent(key);
    if (content) this.memoryCache.set(`offline_${key}`, content);
    return content;
  }

  async isContentCached(key) {
    return OfflineContentManager.isContentCached(key);
  }

  async removeCachedContent(key) {
    this.memoryCache.delete(`offline_${key}`);
    return OfflineContentManager.removeContent(key);
  }

  async clearExpiredContent() {
    return OfflineContentManager.clearExpiredContent();
  }

  async getCacheStats() {
    return OfflineContentManager.getCacheStats();
  }

  // ---- Offline Queue Operations ----
  async addToOfflineQueue(action) {
    return OfflineContentManager.addToQueue(action);
  }

  async getOfflineQueue() {
    return OfflineContentManager.getQueue();
  }

  async processOfflineQueue(processor) {
    const queue = await OfflineContentManager.getQueue();
    const pending = queue.filter(a => a.status === 'pending');
    const results = [];

    for (const action of pending) {
      try {
        const result = await processor(action);
        await OfflineContentManager.markQueueItemProcessed(action.id);
        results.push({ id: action.id, success: true, result });
      } catch (error) {
        results.push({ id: action.id, success: false, error: error.message });
      }
    }

    await OfflineContentManager.clearProcessedQueue();
    return results;
  }

  // ---- Fetch with Cache ----
  async fetchWithCache(key, fetcher, ttl = 3600000) {
    // Try memory cache first
    const memoryCached = this.memoryCache.get(`offline_${key}`);
    if (memoryCached !== undefined) return memoryCached;

    // Try persistent cache
    const cached = await OfflineContentManager.getContent(key);
    if (cached !== null) {
      this.memoryCache.set(`offline_${key}`, cached);
      return cached;
    }

    // Fetch fresh data
    try {
      const freshData = await fetcher();
      await this.cacheContent(key, freshData, ttl);
      return freshData;
    } catch (error) {
      console.error(`[DataManager] Fetch failed for ${key}:`, error);
      throw error;
    }
  }

  // ---- Auth Flow ----
  async login(accessToken, refreshToken, expiresIn, profile, sessionData = {}) {
    await this.saveTokens(accessToken, refreshToken, expiresIn);
    if (profile) await this.saveProfile(profile);
    await this.createSession({
      ...sessionData,
      loggedInAt: Date.now(),
    });
    this.notify('login', { profile });
    return true;
  }

  async logout() {
    // Clear all auth-related data
    await TokenManager.clearTokens();
    await ProfileManager.clearProfile();
    await SessionManager.clearSession();
    await PreferencesManager.clearPreferences();
    await OfflineContentManager.clearAllContent();
    await OfflineContentManager.clearQueue();

    // Clear memory cache
    this.memoryCache.clear();

    this.notify('logout', null);
    return true;
  }

  // ---- Diagnostics ----
  async getDiagnostics() {
    const [tokenInfo, session, settings, cacheStats, queueItems, allKeys] = await Promise.all([
      TokenManager.getTokenInfo(),
      SessionManager.getSession(),
      SettingsManager.getSettings(),
      OfflineContentManager.getCacheStats(),
      OfflineContentManager.getQueue(),
      StorageHelper.getAllKeys(),
    ]);

    return {
      storage: {
        totalKeys: allKeys.length,
        keys: allKeys,
      },
      auth: {
        hasAccessToken: !!tokenInfo.accessToken,
        hasRefreshToken: !!tokenInfo.refreshToken,
        isExpired: tokenInfo.isExpired,
        expiresIn: tokenInfo.expiresIn,
      },
      session: session ? {
        id: session.id,
        duration: Date.now() - (session.createdAt || 0),
        lastActive: session.lastActive,
      } : null,
      settings,
      cache: cacheStats,
      offlineQueue: {
        total: queueItems.length,
        pending: queueItems.filter(a => a.status === 'pending').length,
      },
      memoryCache: this.memoryCache.getStats(),
    };
  }

  // ---- Storage Size Estimation ----
  async estimateStorageSize() {
    const keys = await StorageHelper.getAllKeys();
    let totalSize = 0;

    for (const key of keys) {
      try {
        const value = await AsyncStorage.getItem(key);
        if (value) {
          totalSize += key.length + value.length;
        }
      } catch (e) {
        // Skip failed reads
      }
    }

    return {
      bytes: totalSize * 2, // UTF-16 encoding
      formatted: formatBytes(totalSize * 2),
      itemCount: keys.length,
    };
  }
}

// ==================== Singleton Instance ====================

const dataManager = new DataManager();

// ==================== React Hooks ====================

import { useState, useEffect, useCallback } from 'react';

export function useDataManager() {
  const [isReady, setIsReady] = useState(dataManager.initialized);

  useEffect(() => {
    if (!dataManager.initialized) {
      dataManager.initialize().then(() => setIsReady(true));
    }
  }, []);

  return { dataManager, isReady };
}

export function useProfile() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    dataManager.getProfile().then(p => {
      if (mounted) {
        setProfile(p);
        setLoading(false);
      }
    });

    const unsubscribe = dataManager.subscribe('profileUpdated', (updatedProfile) => {
      if (mounted) setProfile(updatedProfile);
    });

    return () => {
      mounted = false;
      unsubscribe();
    };
  }, []);

  const updateProfile = useCallback(async (updates) => {
    return dataManager.updateProfile(updates);
  }, []);

  return { profile, loading, updateProfile };
}

export function useSettings() {
  const [settings, setSettings] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    dataManager.getSettings().then(s => {
      if (mounted) {
        setSettings(s);
        setLoading(false);
      }
    });

    const unsubscribe = dataManager.subscribe('settingsUpdated', (updatedSettings) => {
      if (mounted) setSettings(updatedSettings);
    });

    return () => {
      mounted = false;
      unsubscribe();
    };
  }, []);

  const updateSetting = useCallback(async (key, value) => {
    return dataManager.updateSetting(key, value);
  }, []);

  return { settings, loading, updateSetting };
}

export function useTheme() {
  const { settings, loading, updateSetting } = useSettings();

  const setTheme = useCallback(async (theme) => {
    return updateSetting('theme', theme);
  }, [updateSetting]);

  return {
    theme: settings?.theme || 'system',
    loading,
    setTheme,
  };
}

export function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;

    const checkAuth = async () => {
      const token = await dataManager.getAccessToken();
      const expired = await dataManager.isTokenExpired();
      if (mounted) {
        setIsAuthenticated(!!token && !expired);
        setLoading(false);
      }
    };

    checkAuth();

    const unsubLogin = dataManager.subscribe('login', () => {
      if (mounted) setIsAuthenticated(true);
    });

    const unsubLogout = dataManager.subscribe('logout', () => {
      if (mounted) setIsAuthenticated(false);
    });

    const unsubTokens = dataManager.subscribe('tokensUpdated', () => {
      if (mounted) checkAuth();
    });

    return () => {
      mounted = false;
      unsubLogin();
      unsubLogout();
      unsubTokens();
    };
  }, []);

  const login = useCallback(async (accessToken, refreshToken, expiresIn, profile, sessionData) => {
    return dataManager.login(accessToken, refreshToken, expiresIn, profile, sessionData);
  }, []);

  const logout = useCallback(async () => {
    return dataManager.logout();
  }, []);

  return { isAuthenticated, loading, login, logout };
}

export function useCachedContent(key, fetcher, ttl) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await dataManager.fetchWithCache(key, fetcher, ttl);
      setData(result);
    } catch (err) {
      setError(err);
    } finally {
      setLoading(false);
    }
  }, [key, fetcher, ttl]);

  useEffect(() => {
    refresh();
  }, [refresh]);

  return { data, loading, error, refresh };
}

export function useOfflineQueue() {
  const [queue, setQueue] = useState([]);
  const [processing, setProcessing] = useState(false);

  const loadQueue = useCallback(async () => {
    const q = await dataManager.getOfflineQueue();
    setQueue(q);
  }, []);

  useEffect(() => {
    loadQueue();
  }, [loadQueue]);

  const addToQueue = useCallback(async (action) => {
    await dataManager.addToOfflineQueue(action);
    await loadQueue();
  }, [loadQueue]);

  const processQueue = useCallback(async (processor) => {
    setProcessing(true);
    try {
      const results = await dataManager.processOfflineQueue(processor);
      await loadQueue();
      return results;
    } finally {
      setProcessing(false);
    }
  }, [loadQueue]);

  return { queue, processing, addToQueue, processQueue, refreshQueue: loadQueue };
}

// ==================== Exports ====================

export {
  STORAGE_KEYS,
  DEFAULT_SETTINGS,
  DEFAULT_PREFERENCES,
  StorageHelper,
  MemoryCache,
  TokenManager,
  ProfileManager,
  PreferencesManager,
  SessionManager,
  SettingsManager,
  OfflineContentManager,
  DataManager,
};

export default dataManager;